use rusqlite::{Connection, params, Result};

pub fn authenticate_user(conn: &Connection, username: &str, password: &str) -> Result<bool> {
    let mut stmt = conn.prepare(
        "SELECT COUNT(*) FROM users WHERE username = ?1 AND password = ?2"
    )?;

    let count: i64 = stmt.query_row(params![username, password], |row| {
        row.get(0)
    })?;

    Ok(count > 0)
}

pub fn setup_database(conn: &Connection) -> Result<()> {
    conn.execute(
        "CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            username TEXT NOT NULL UNIQUE,
            password TEXT NOT NULL
        )",
        [],
    )?;
    Ok(())
}

pub fn add_user(conn: &Connection, username: &str, password_hash: &str) -> Result<()> {
    conn.execute(
        "INSERT INTO users (username, password) VALUES (?1, ?2)",
        params![username, password_hash],
    )?;
    Ok(())
}

